export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const today = new Date();
  const cutoff = new Date(today);
  cutoff.setDate(cutoff.getDate() + 14);
  const cutoffIso = cutoff.toISOString();

  const readBatch = await callMcpSkillsParallel({
    label: "politics-live-14d-discovery",
    calls: [
      {
        key: "top-markets",
        toolId,
        toolName: "get_top_markets",
        args: {
          category: "politics",
          sortBy: "ending_soon",
          endDateBefore: cutoffIso,
          includeEnded: false,
          includeNearResolved: false,
          limit: 100
        }
      },
      {
        key: "events",
        toolId,
        toolName: "get_events",
        args: {
          active: true,
          closed: false,
          limit: 100
        }
      }
    ]
  });

  const topMarketsRes =
    readBatch.results.find((entry) => entry.key === "top-markets")?.status === "fulfilled"
      ? readBatch.results.find((entry) => entry.key === "top-markets")?.value
      : null;

  const eventsRes =
    readBatch.results.find((entry) => entry.key === "events")?.status === "fulfilled"
      ? readBatch.results.find((entry) => entry.key === "events")?.value
      : null;

  const markets = Array.isArray(topMarketsRes?.markets) ? topMarketsRes.markets : [];
  const events = Array.isArray(eventsRes?.events) ? eventsRes.events : [];

  const livePoliticsWithin14Days = markets.filter((m) => {
    if (!m || m.category !== "politics") return false;
    if (!m.endDate) return false;
    const end = new Date(m.endDate);
    return Number.isFinite(end.getTime()) && end <= cutoff;
  });

  const semanticCandidates = pickTopSemanticCandidates({
    target: "live politics markets ending within 14 days",
    candidates: livePoliticsWithin14Days,
    requiredTerms: ["politics"],
    avoidTerms: ["resolved", "closed"],
    limit: livePoliticsWithin14Days.length
  });

  const shortlisted = Array.isArray(semanticCandidates) && semanticCandidates.length > 0
    ? semanticCandidates
    : livePoliticsWithin14Days;

  const activityReadouts = [];
  for (const market of shortlisted) {
    if (!market?.conditionId) continue;

    const activity = await callMcpSkill({
      toolId,
      toolName: "summarize_live_market_activity",
      args: {
        conditionId: market.conditionId,
        tradeLimit: 20,
        sortBy: "ending_soon",
        endingWithinDays: 14
      }
    });

    const totalVolume = activity?.tradesSummary?.totalVolume;
    const openInterest = activity?.openInterest?.value;
    const buyVolume = activity?.tradesSummary?.buyVolume;
    const sellVolume = activity?.tradesSummary?.sellVolume;
    const totalTrades = activity?.tradesSummary?.totalTrades;

